// // This module converts an 8-bit binary number to its equivalent 8-bit Gray code representation by performing a left arithmetic shift and then applying a bitwise AND operation.
module top_module(
    B,
    G
);input [7:0] B;
output [7:0] G;
wire [7:0] G;




assign G = ((B >>> 1) ^ B);

endmodule
